<?php
namespace App\Http\Resources; use Illuminate\Http\Request; use Illuminate\Http\Resources\Json\JsonResource;
class CardResource extends JsonResource { public function toArray(Request $request): array { $image=$this->image && $this->image !== '0' ? $this->image : null; if ($image && !str_starts_with($image, 'http://') && !str_starts_with($image, 'https://')) { $image=\Illuminate\Support\Facades\Storage::disk('public')->url(ltrim(preg_replace('#^storage/#', '', $image), '/')); } return ['id'=>$this->id,'title'=>$this->title,'subtitle'=>$this->subtitle,'score'=>$this->score,'image'=>$image,'deck'=>$this->stack?->slug ?? $this->deck,'stack'=>$this->stack ? ['id'=>$this->stack->id,'name'=>$this->stack->name,'slug'=>$this->stack->slug] : null]; } }
